diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..525951b18130 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3344,6 +3344,88 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Neg->takeName(BO);
         return new ICmpInst(Pred, BOp0, Neg);
       }
+    } else if (BO->hasOneUse()) {
+      // (ext i1 A) + (ext i1 B) == C --> boolean expression
+      // where ext is zext or sext.
+      auto matchBoolExt = [](Value *V, Value *&Op, bool &IsSExt) -> bool {
+        if (match(V, m_ZExt(m_Value(Op)))) {
+          IsSExt = false;
+          return Op->getType()->isIntOrIntVectorTy(1);
+        }
+        if (match(V, m_SExt(m_Value(Op)))) {
+          IsSExt = true;
+          return Op->getType()->isIntOrIntVectorTy(1);
+        }
+        return false;
+      };
+
+      Value *A, *B;
+      bool IsSExt0, IsSExt1;
+      if (matchBoolExt(BOp0, A, IsSExt0) &&
+          matchBoolExt(BOp1, B, IsSExt1)) {
+        // Compute the four possible sums:
+        // S00 = ext0(0) + ext1(0) = 0 + 0 = 0
+        // S01 = ext0(0) + ext1(1) = 0 + V1
+        // S10 = ext0(1) + ext1(0) = V0 + 0
+        // S11 = ext0(1) + ext1(1) = V0 + V1
+        // where V = 1 for zext, AllOnes for sext.
+        unsigned BW = C.getBitWidth();
+        APInt V0 = IsSExt0 ? APInt::getAllOnes(BW) : APInt(BW, 1);
+        APInt V1 = IsSExt1 ? APInt::getAllOnes(BW) : APInt(BW, 1);
+
+        bool Eq00 = (APInt(BW, 0) == C);
+        bool Eq01 = (V1 == C);
+        bool Eq10 = (V0 == C);
+        bool Eq11 = (V0 + V1 == C);
+
+        // Helper to create the appropriate boolean expression.
+        auto createBoolExpr = [&](bool ForNE) -> Value * {
+          bool T00 = ForNE ? !Eq00 : Eq00;
+          bool T01 = ForNE ? !Eq01 : Eq01;
+          bool T10 = ForNE ? !Eq10 : Eq10;
+          bool T11 = ForNE ? !Eq11 : Eq11;
+
+          int Count = T00 + T01 + T10 + T11;
+          if (Count == 0)
+            return Builder.getFalse();
+          if (Count == 4)
+            return Builder.getTrue();
+
+          // Count == 2 with (0,1) and (1,0) -> xor A, B
+          if (Count == 2 && T01 && T10 && !T00 && !T11)
+            return Builder.CreateXor(A, B);
+
+          // Count == 2 with (0,0) and (1,1) -> not(xor A, B)
+          if (Count == 2 && T00 && T11 && !T01 && !T10)
+            return Builder.CreateNot(Builder.CreateXor(A, B));
+
+          // Count == 1: single AND term
+          Value *TermA = A, *TermB = B;
+          if (Count == 1) {
+            if (T00) { TermA = Builder.CreateNot(A); TermB = Builder.CreateNot(B); }
+            else if (T01) { TermA = Builder.CreateNot(A); }
+            else if (T10) { TermB = Builder.CreateNot(B); }
+            // T11: A and B as-is
+            return Builder.CreateAnd(TermA, TermB);
+          }
+
+          // Count == 3: single OR term (De Morgan of Count==1 for complement)
+          Value *OrA = A, *OrB = B;
+          if (Count == 3) {
+            if (!T00) { OrA = Builder.CreateNot(A); OrB = Builder.CreateNot(B); }
+            else if (!T01) { OrA = Builder.CreateNot(A); }
+            else if (!T10) { OrB = Builder.CreateNot(B); }
+            // !T11: OR of negated terms
+            return Builder.CreateOr(OrA, OrB);
+          }
+
+          llvm_unreachable("Unexpected count in boolean extension fold");
+          return nullptr;
+        };
+
+        return replaceInstUsesWith(Cmp, createBoolExpr(isICMP_NE));
+      }
+    }
     }
     break;
   }

