          Value *Result = nullptr;
          auto addTerm = [&](Value *Term) {
            if (!Result) Result = Term;
            else Result = Builder.CreateOr(Result, Term);
          };

          auto createAnd = [&](bool NotA, bool NotB) -> Value * {
